```javascript
// Store user corrections in IndexedDB
const LEARNING_STORE = 'categoryLearning';

async function learnFromCorrection(description, correctCategory) {
    const db = await openDB();
    const tx = db.transaction(LEARNING_STORE, 'readwrite');
    const store = tx.objectStore(LEARNING_STORE);

    // Store pattern
    await store.put({
        pattern: description.toLowerCase(),
        category: correctCategory,
        timestamp: Date.now()
    });
}

async function getLearnedCategory(description) {
    const db = await openDB();
    const tx = db.transaction(LEARNING_STORE, 'readonly');
    const store = tx.objectStore(LEARNING_STORE);
    const all = await store.getAll();

    // Find matching patterns
    const desc = description.toLowerCase();
    const matches = all.filter(item => desc.includes(item.pattern));

    if (matches.length > 0) {
        // Return most recent match
        return matches.sort((a, b) => b.timestamp - a.timestamp)[0].category;
    }

    return null;
}
```

